<template>
	<view>
		<view class="list-box">
			<template v-if="list.length">
				<view class="list-item" v-for="item,index in list" :key="index" @click="handelItemClick(item)">
					<view v-show="isManage" class="checker" :class="{'checker-on':checkSelected(item.id)}"
						@click="handelChecker(item.id)">
						<u-icon name="checkmark-circle" size="30"></u-icon>
					</view>
					<view class="column-id">
						{{item.id}}
					</view>
					<view class="column-name">
						<view class="line2 goods-name">{{item.goods_name}}</view>
						<view class="line2 short-name">{{item.goods_short_name}}</view>
					</view>
					<view class="column-op" v-show="!isManage">
						<slot name='opts' :row="item"></slot>
					</view>
				</view>
			</template>
			<template v-else>
				<view class="empty-data">
					<u-empty text="数据为空" mode="data"></u-empty>
				</view>
			</template>
		</view>
	</view>
</template>

<script>
	export default {
		components: {

		},
		props: {
			list: {
				type: Array,
				default: () => []
			},
			selectedIds: {
				type: Array,
				default: () => []
			},
			isManage: {
				type: Boolean,
				default: false,
			},
		},
		data() {
			return {
				currSelectedIds: []
			};
		},
		computed: {

		},
		watch: {
			selectedIds: {
				handler(nv) {
					this.currSelectedIds = this.$u.deepClone(nv)
				},
				immediate: true,
			},
		},
		created() {

		},
		mounted() {

		},
		methods: {
			// checker被点击
			handelChecker(cid) {
				let copy_ids = this.$u.deepClone(this.currSelectedIds)
				let index = copy_ids.findIndex(id => id == cid)
				if (index != -1) {
					copy_ids.splice(index, 1)
				} else {
					copy_ids.push(cid)
				}

				this.currSelectedIds = copy_ids
				this.$emit('selected-ids', {
					selectedIds: copy_ids,
					isSelectAll: this.checkAllSelected()
				})
			},
			// 判断是否已经选中
			checkSelected(cid) {
				let copy_ids = this.$u.deepClone(this.currSelectedIds)
				let flag = false
				let index = copy_ids.findIndex(id => id == cid)
				if (index == -1) {
					flag = false
				} else {
					flag = true
				}
				return flag
			},
			// 判断是否全部选中
			checkAllSelected() {
				if (this.list.length == this.currSelectedIds.length)
					return true
				else
					return false
			},
			// item点击
			handelItemClick(row) {

			},
		},
	};
</script>

<style scoped lang="scss" scoped>
	.checker {
		padding-right: 20rpx;
		color: #B0B0B0 !important;
	}

	.checker-on {
		color: #F05C02 !important;
	}

	.list-box {
		display: flex;
		flex-direction: column;

		.list-item {
			position: relative;
			display: flex;
			align-items: center;
			gap: 20rpx;
			background-color: #fff;
			padding: 20rpx;
			cursor: pointer;

			.column-id {
				min-width: 100rpx;
			}

			.column-name {
				flex: 1;

				.goods-name {
					font-size: 30rpx;
					font-weight: 800;
				}

				.short-name {
					font-size: 24rpx;
				}
			}

			.column-op {
				text-align: right;
				min-width: 100rpx;
			}
		}

		.list-item~.list-item {
			border-top: 1px solid #F5F5F5;
		}
	}
</style>