<template>
	<u-mask :show="show" @click="show = false" :z-index="979">
		<view class="warp" @click.stop>
			<u-sticky>
				<!-- 只能有一个根元素 -->
				<view class="sticky">
					<u-form :model="queryForm" ref="uForm" :label-width="140">
						<u-form-item label="商品ID"><u-input v-model="queryForm.goods_id" /></u-form-item>
						<u-form-item label="商品名称"><u-input v-model="queryForm.goods_name" /></u-form-item>
						<u-form-item label="商品分类">
							<text v-if="cateText" @click="showCatePicker = true">{{cateText}}</text>
							<text style="color: rgb(192, 196, 204); display: block; width: 100%;"
								@click="showCatePicker = true" v-else>请选择</text>
							<u-select v-model="showCatePicker" :default-value="defaultCateValue" :list="cateList"
								mode="mutil-column-auto" @confirm="confirm" value-name="id" label-name="name"
								child-name="children"></u-select>
						</u-form-item>
						<u-form-item label="商品类型">
							<u-input :value="goodsTypeText" type="select" @click="showGoodsType = true" />
							<u-action-sheet :list="goodsTypeList" v-model="showGoodsType"
								@click="handelGoodsTypeChange"></u-action-sheet>
						</u-form-item>
						<u-form-item label="" :border-bottom="false">
							<u-button @click="submit">提交</u-button>
							<u-button @click="show=false">取消</u-button>
						</u-form-item>
					</u-form>
				</view>
			</u-sticky>
		</view>
	</u-mask>
</template>

<script>
	export default {
		components: {

		},
		props: {

		},
		data() {
			return {
				show: false,
				queryForm: {
					page: 0,
					limit: 20,
					goods_id: '',
					goods_name: '',
					category_ids: [],
					goods_type: '',
				},

				showCatePicker: false,
				cateText: '',
				cateList: [],

				goodsTypeList: [{
						text: '卡密',
						value: 1,
					},
					{
						text: '手工',
						value: 2,
					},
					{
						text: '实物',
						value: 3,
					},
					{
						text: '清空',
						color: '#fa3534'
					}
				],
				showGoodsType: false,
			};
		},
		computed: {
			defaultCateValue() {
				return this.getSelectValueIndex(this.cateList, this.$u.deepClone(this.queryForm.category_ids) || [])
			},
			goodsTypeText: {
				get() {
					if (this.queryForm.goods_type != '') {
						let find = this.goodsTypeList.find(item => item.value == this.queryForm.goods_type)
						return find.text
					} else {
						return ''
					}
				}
			},
		},
		watch: {

		},
		created() {

		},
		mounted() {

		},
		methods: {
			getSelectValueIndex(list = [], ids = [], idx_arr = []) {
				let id = ids.shift()
				let index = list.findIndex(item => item.id == id)				
				if (index != -1) {
					idx_arr.push(index)
					this.getSelectValueIndex(list[index].children, ids, idx_arr)
					return idx_arr
				} else {
					return []
				}
			},
			showEdit(queryForm) {
				this.queryForm = Object.assign({}, {
					...queryForm
				})
				this.show = true
				this.loadData()
			},
			loadData() {
				this.$u.api.goodsCardBatchGetCate().then(res => {
					this.cateList = res.category_list
				})
			},
			handelGoodsTypeChange(e) {
				if (this.goodsTypeList[e].value)
					this.queryForm.goods_type = this.goodsTypeList[e].value
				else
					this.queryForm.goods_type = ''
			},
			// 提交
			submit() {
				this.$emit('ok', this.queryForm)
				this.show = false
			},
			// 分类回调
			confirm(e) {
				this.cateText = e.map(item => item.label).join(',')
				this.queryForm.category_ids = e.map(item => item.value)
			},
		},
	};
</script>

<style scoped lang="scss" scoped>
	.warp {}

	.sticky {
		padding: 20rpx;
		background-color: #fff;
	}

	::v-deep {
		.u-sticky {
			left: 0 !important;
			width: 100% !important;
		}

		.u-sticky-wrap {
			height: auto !important;
		}
	}
</style>