<template>
	<view class="">
		<u-navbar title="" back-text="关联商品" :z-index="980" :custom-back="$util.back">
			<template #right>
				<view class="navbar-right">
					<view class="btn-item" @click="handelFilterClick">
						<u-icon name="search"></u-icon>
						<text>筛选</text>
					</view>
					<view class="btn-item" @click="handelManagerClick">
						<u-icon name="list-dot"></u-icon>
						<text v-if="isManage">取消</text>
						<text v-else>管理</text>
					</view>
					<view class="btn-item" @click="handelAddClick">
						<u-icon name="plus"></u-icon>
						<text>新增</text>
					</view>
				</view>
			</template>
		</u-navbar>
		<scroll-view @touchmove.stop :scroll-y="true" class="scroll_content" :rebound="false"
			:style="{height:scrollHeight+'px'}" @scrolltolower="lower">
			<card-group-goods-list :list="list" :selectedIds="selectedIds" :isManage="isManage"
				@selected-ids="handelSelectedIdsChange">
				<template #opts="{row}">
					<view class="btn bg-green" @click="handelEdit(row)">修改</view>
					<view class="btn bg-red" @click="handelDelete(row)">删除</view>
				</template>
			</card-group-goods-list>
			<u-loadmore :status="loading" icon-type="circle" @loadmore="fetchData" v-if="list.length" />
		</scroll-view>
		<view class="footer" v-if="isManage">
			<view class="wrap">
				<view class="checker" :class="{'checker-on':isSelectAll}" @click="handelAllSelected">
					<u-icon name="checkmark-circle" size="30"></u-icon>
				</view>
				<view class="btns">
					<view class="btn-item bg-red" @click="handelDelete()">删除</view>
				</view>
			</view>
		</view>
		<card-group-goods-filter ref="card-group-goods-filter" @ok="handelFilterChange" />
		<card-group-goods-edit ref="card-group-goods-edit" @ok="handelEditOk" />
	</view>
</template>

<script>
	import CardGroupGoodsList from './components/card-group-goods-list'
	import CardGroupGoodsFilter from './components/card-group-goods-filter'
	import CardGroupGoodsEdit from './components/card-group-goods-edit'
	export default {
		components: {
			'card-group-goods-list': CardGroupGoodsList,
			'card-group-goods-filter': CardGroupGoodsFilter,
			'card-group-goods-edit': CardGroupGoodsEdit,
		},
		data() {
			return {
				scrollHeight: 0,

				queryForm: {
					page: 1,
					limit: 20,
					goods_id: '',
					goods_name: '',
					category_ids: [], //分类ID数组
					goods_type: '',
					set_type: 0, //0默认 1=已设置 2=未设置
					batch_id: '', //卡组ID
				},

				list: [], //卡组列表
				total: 0,
				loading: 'loadmore',

				isManage: false,
				isSelectAll: false,
				selectedIds: [],
			};
		},
		onReady() {
			this.$nextTick(() => {
				uni.createSelectorQuery().select(".scroll_content").boundingClientRect(res => {
					this.scrollHeight = this.deviceInfo.screenHeight - res.top
				}).exec()
			})
		},
		onLoad(e) {
			const {
				id
			} = e
			if (!id) {
				this.$util.msg('卡组ID不能为空')
				setTimeout(() => {
					this.$util.back()
				}, 500)
				return
			}
			this.queryForm.batch_id = id
			this.queryForm.set_type = 1
			this.fetchData()
		},
		onHide() {
			// this.queryForm = this.$options.data().queryForm
			this.isManage = false
		},
		methods: {
			async fetchData() {
				if (this.loading == 'nomore')
					return
				this.loading = 'loading'
				const {
					list,
					total,
					url
				} = await this.$u.api.getCardBatchGoods(this.queryForm)
				this.total = total
				this.url = url
				if (list.length) {
					this.list = this.list.concat(list)
				}
				if (list.length < this.queryForm.limit) {
					this.loading = 'nomore'
				} else {
					this.loading = 'loadmore'
				}
			},
			reloadData() {
				this.queryForm.page = 1
				this.loading = 'loadmore'
				this.list = []
				this.fetchData()
			},
			// 加载下一页
			lower() {
				if (this.loading == 'nomore')
					return
				this.queryForm.page++
				this.fetchData()
			},
			// 筛选点击
			handelFilterClick() {
				this.$refs['card-group-goods-filter'].showEdit(this.queryForm)
			},
			// 筛选回调
			handelFilterChange(e) {
				this.queryForm = Object.assign({}, e)
				this.reloadData()
			},
			// 删除点击
			async handelDelete(row) {
				let arr = []
				if (row) {
					let index = this.list.findIndex(item => item.id == row.id)
					await this.$u.api.getCardBatchGoodsDelete({
						id: this.queryForm.batch_id,
						goods_ids: [row.id]
					})
					this.list.splice(index, 1)
					arr = this.$u.deepClone(this.list)
				} else {
					if (!this.selectedIds.length) {
						this.$util.msg('未选择数据')
						return
					}
					let ids = []
					this.list.forEach(item => {
						if (!this.selectedIds.includes(item.id))
							arr.push(item)
						else
							ids.push(item.id)
					})
					await this.$u.api.getCardBatchGoodsDelete({
						id: this.queryForm.batch_id,
						goods_ids: ids,
					})
				}
			},
			// 新增点击
			handelAddClick() {
				this.$util.on(`/pages/ucenter_sub/exchange/card_group_goods_add?id=${this.queryForm.batch_id}`)
			},
			// 管理点击
			handelManagerClick() {
				if (!this.list.length) {
					this.$util.msg('列表数据为空')
					return
				}
				this.isManage = !this.isManage
				this.isSelectAll = false
				this.selectedIds = []
			},
			// 全选
			handelAllSelected() {
				this.isSelectAll = !this.isSelectAll
				if (this.isSelectAll) {
					let ids = []
					this.list.map(item => {
						ids.push(item.id)
					})
					this.selectedIds = ids
				} else {
					this.selectedIds = []
				}
			},
			// 选中改变回调
			handelSelectedIdsChange({
				selectedIds,
				isSelectAll
			}) {
				this.selectedIds = selectedIds
				this.isSelectAll = isSelectAll
			},
			// 页面传参回调函数,实现新增卡组商品
			async setGoodsData({
				receivedParams
			}) {
				const ids = receivedParams.map(item => item.id)
				await this.$u.api.getCardBatchGoodsAdd({
					id: this.queryForm.batch_id,
					goods_ids: ids,
				})
				this.reloadData()
			},
			// 修改
			handelEdit(e) {
				this.$refs['card-group-goods-edit'].showEdit(e)
			},
			// 修改回调
			async handelEditOk(e) {
				await this.$u.api.goodsCardGoodsEdit({
					field: 'goods_short_name',
					goods_ids: e.id,
					value: e.goods_short_name,
					id: this.queryForm.batch_id
				})
				let find = this.list.find(item => item.id == e.id)
				find.goods_short_name = e.goods_short_name
			}
		},
	}
</script>

<style lang="scss" scoped scoped>
	.checker {
		padding-right: 20rpx;
		color: #B0B0B0 !important;
	}

	.checker-on {
		color: #F05C02 !important;
	}

	.navbar-right {
		margin-right: 18rpx;
		display: flex;
		gap: 20rpx;

		.btn-item {}

		.btn-item:active {
			opacity: .6;
		}
	}

	.footer {
		position: fixed;
		bottom: 0;
		z-index: 11;
		width: 100%;
		height: 104rpx;
		background-color: #fff;
		border-top: 1px solid #ccc;
		flex-wrap: nowrap;
		justify-content: space-between;
		align-items: center;
		display: flex;
		padding: 20rpx;

		.wrap {
			width: 100%;
			display: flex;
			align-items: center;

			.checker {}

			.btns {
				flex: 1;
				display: flex;
				gap: 10rpx;
				justify-content: flex-end;

				.btn-item {
					white-space: nowrap;
					border-radius: 20rpx;
					padding: 2rpx 20rpx;
					color: #fff;
					display: block;
					text-align: center;
					width: 100rpx;
				}

				.btn-item:active {
					opacity: .6;
				}
			}
		}
	}
</style>