<template>
	<view>
		<u-popup v-model="popupShow" mode="bottom" :z-index="981" :custom-style="customStyle"
			:mask-custom-style="{background: 'rgba(0, 0, 0, 0.4)'}" :border-radius="20" :closeable="true" @close="close"
			@open="open">
			<view class="popup-title">{{form.goods_name}}</view>
			<view class="popup-content">
				<scroll-view @touchmove.stop scroll-y class="scroll_content" :style="{height:'600rpx'}">
					<u-form :model="form" ref="uForm" label-width="140">
						<u-form-item label="商品ID" prop="goods_id">
							<u-input v-model="form.id" disabled />
						</u-form-item>
						<u-form-item label="商品名称" prop="goods_name">
							<u-input v-model="form.goods_name" disabled />
						</u-form-item>
						<u-form-item label="商品简称" prop="goods_short_name">
							<u-input v-model="form.goods_short_name" placeholder="请输入商品简称" />
						</u-form-item>
					</u-form>
				</scroll-view>
			</view>
			<view class="popup-footer">
				<u-button type="warning" shape="circle" @click="handelOk">确 定</u-button>
			</view>
		</u-popup>
	</view>
</template>

<script>
	export default {
		props: {
			customStyle: {
				type: Object,
				default: () => {}
			}
		},
		data() {
			return {
				popupShow: false,

				form: {
					goods_short_name: ''
				},
				rules: {
					goods_short_name: [{
						max: 20,
						message: '商品简称最大长度限制20个字符',
						trigger: ['blur', 'change']
					}]
				},
			};
		},
		mounted() {

		},
		methods: {
			showEdit(e) {
				this.form = Object.assign({}, e)
				this.popupShow = true
			},
			open() {
				this.$refs.uForm.setRules(this.rules)
			},
			close() {
				this.form = this.$options.data().form
			},
			handelOk() {
				this.$refs.uForm.validate(valid => {
					if (valid) {
						this.$emit('ok', this.form)
						this.popupShow = false
					}
				});
			},
		}
	}
</script>

<style scoped lang="scss" scoped>
	.popup-title {
		height: 100rpx;
		line-height: 100rpx;
		text-align: center;
		font-weight: bold;
	}

	.popup-content {
		padding: 20rpx;
		min-height: 600rpx;

		.wrap {
			background-color: #f4f4f5;
			height: 300rpx;
			overflow-y: auto;
		}
	}

	.popup-footer {
		padding: 40rpx;
	}
</style>